SELECT * FROM news 
WHERE 1 = 1


    AND is_notice = #{isNotice}



    AND (
        title LIKE CONCAT('%', #{keyword}, '%')
        OR content LIKE CONCAT('%', #{keyword}, '%')
    )



    AND publish_status = #{publishStatus}



    AND news_type = #{newsType}




        ORDER BY ${orderBy}


        ORDER BY publish_date DESC




    LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM news 
WHERE 1 = 1

    AND is_notice = #{isNotice}


    AND (
        title LIKE CONCAT('%', #{keyword}, '%')
        OR content LIKE CONCAT('%', #{keyword}, '%')
    )


    AND publish_status = #{publishStatus}


    AND news_type = #{newsType}
